import heapq

class PriorityQueue:
    def __init__(self):
        self._queue = []
        self._index = 0

    def push(self, item, priority):
        heapq.heappush(self._queue, (priority, self._index, item))
        self._index += 1

    def pop(self):
        if not self._queue:
            raise IndexError("pop from an empty priority queue")
        return heapq.heappop(self._queue)[-1]

    def peek(self):
        if not self._queue:
            raise IndexError("peek from an empty priority queue")
        return self._queue[0][-1]

import time

class CacheTTL:
    def __init__(self):
        self._store = {}

    def set(self, key, value, ttl):
        if ttl <= 0:
            self.delete(key)
            return
        expiration_time = time.time() + ttl
        self._store[key] = (value, expiration_time)

    def get(self, key):
        if key in self._store:
            value, expiration_time = self._store[key]
            if time.time() < expiration_time:
                return value
            else:
                del self._store[key]
        return None

    def delete(self, key):
        if key in self._store:
            del self._store[key]

    def clear_expired(self):
        current_time = time.time()
        keys_to_delete = [key for key, (_, exp_time) in self._store.items() if current_time >= exp_time]
        for key in keys_to_delete:
            del self._store[key]

