type EventMap = Record<string, any>;
type EventListener<T> = [T] extends [never] 
  ? () => void 
  : (payload: T) => void;

export class EventEmitter<Events extends EventMap> {
  private listeners: {
    [K in keyof Events]?: Set<EventListener<Events[K]>>;
  } = {};

  on<K extends keyof Events>(event: K, listener: EventListener<Events[K]>): this {
    if (!this.listeners[event]) {
      this.listeners[event] = new Set();
    }
    this.listeners[event]!.add(listener);
    return this;
  }

  off<K extends keyof Events>(event: K, listener: EventListener<Events[K]>): this {
    this.listeners[event]?.delete(listener);
    return this;
  }

  emit<K extends keyof Events>(event: K, ...payload: [Events[K]] extends [never] ? [] : [Events[K]]): boolean {
    const eventListeners = this.listeners[event];
    if (!eventListeners || eventListeners.size === 0) {
      return false;
    }

    eventListeners.forEach(listener => {
      listener(...(payload as [Events[K]]));
    });

    return true;
  }

  once<K extends keyof Events>(event: K, listener: EventListener<Events[K]>): this {
    const wrapper: EventListener<Events[K]> = ((...args: any[]) => {
      this.off(event, wrapper);
      listener(...args);
    }) as EventListener<Events[K]>;

    return this.on(event, wrapper);
  }

  removeAllListeners<K extends keyof Events>(event?: K): this {
    if (event) {
      delete this.listeners[event];
    } else {
      this.listeners = {};
    }
    return this;
  }
}

import math
import mmh3

class BloomFilter:
    def __init__(self, items_count, fp_prob=0.01):
        self.fp_prob = fp_prob
        self.size = self._get_size(items_count, fp_prob)
        self.hash_count = self._get_hash_count(self.size, items_count)
        self.bit_array = [False] * self.size

    def add(self, item):
        for i in range(self.hash_count):
            digest = mmh3.hash(item, i) % self.size
            self.bit_array[digest] = True

    def contains(self, item):
        for i in range(self.hash_count):
            digest = mmh3.hash(item, i) % self.size
            if not self.bit_array[digest]:
                return False
        return True

    @staticmethod
    def _get_size(n, p):
        return int(-(n * math.log(p)) / (math.log(2) ** 2))

    @staticmethod
    def _get_hash_count(m, n):
        return int((m / n) * math.log(2))

def dfs(graph, start, visited=None):
    if visited is None:
        visited = set()
    visited.add(start)
    for neighbor in graph.get(start, []):
        if neighbor not in visited:
            dfs(graph, neighbor, visited)
    return visited

