import (
	"encoding/csv"
	"fmt"
	"os"
)

type Record struct {
	Field1 string
	Field2 string
	Field3 string
}

func ReadCSV(filename string) ([]Record, error) {
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	reader := csv.NewReader(file)
	rows, err := reader.ReadAll()
	if err != nil {
		return nil, err
	}

	var records []Record
	for i, row := range rows {
		if i == 0 {
			continue
		}
		rec := Record{}
		if len(row) > 0 {
			rec.Field1 = row[0]
		}
		if len(row) > 1 {
			rec.Field2 = row[1]
		}
		if len(row) > 2 {
			rec.Field3 = row[2]
		}
		records = append(records, rec)
	}

	return records, nil
}

func main() {
	recs, err := ReadCSV("data.csv")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("%+v\n", recs)
}

