import random

class MusicPlaylist:
    def __init__(self):
        self._playlist = []
        self._current_index = -1

    def add(self, song):
        self._playlist.append(song)
        if self._current_index == -1:
            self._current_index = 0

    def remove(self, song):
        if song in self._playlist:
            song_index = self._playlist.index(song)
            self._playlist.remove(song)

            if not self._playlist:
                self._current_index = -1
            elif song_index < self._current_index:
                self._current_index -= 1
            elif song_index == self._current_index and self._current_index >= len(self._playlist):
                self._current_index = 0

    def shuffle(self):
        if len(self._playlist) > 1:
            current_song = self._playlist[self._current_index]
            remaining_songs = [s for i, s in enumerate(self._playlist) if i != self._current_index]
            random.shuffle(remaining_songs)
            self._playlist = [current_song] + remaining_songs
            self._current_index = 0

    def next(self):
        if not self._playlist:
            return None

        self._current_index = (self._current_index + 1) % len(self._playlist)
        return self._playlist[self._current_index]

