def quicksort[T <% Ordered[T]](list: List[T]): List[T] = {
  list match {
    case Nil => Nil
    case pivot :: tail =>
      val (less, greater) = tail.partition(_ < pivot)
      quicksort(less) ::: pivot :: quicksort(greater)
  }
}

