def mergesort(arr):
    if len(arr) <= 1:
        return arr

    mid = len(arr) // 2
    left = mergesort(arr[:mid])
    right = mergesort(arr[mid:])

    return merge(left, right)

def merge(left, right):
    result = []
    i = j = 0

    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1

    result.extend(left[i:])
    result.extend(right[j:])

    return result

import io

class CSVParser:
    def __init__(self, delimiter=',', quote_char='"', escape_char='\\'):
        self.delimiter = delimiter
        self.quote_char = quote_char
        self.escape_char = escape_char

    def parse(self, text):
        if not text:
            return []

        stream = io.StringIO(text)
        return list(self.parse_stream(stream))

    def parse_stream(self, stream):
        fields = []
        current_field = []
        in_quotes = False
        next_char_escaped = False

        while True:
            char = stream.read(1)
            if not char:
                break

            if next_char_escaped:
                current_field.append(char)
                next_char_escaped = False
                continue

            if char == self.escape_char:
                next_char_escaped = True
                continue

            if char == self.quote_char:
                if in_quotes:
                    peek_char = stream.read(1)
                    if peek_char == self.quote_char:
                        current_field.append(self.quote_char)
                    else:
                        in_quotes = False
                        if peek_char:
                            stream.seek(stream.tell() - 1)
                else:
                    in_quotes = True
                continue

            if not in_quotes and char == self.delimiter:
                fields.append("".join(current_field))
                current_field = []
                continue

            if not in_quotes and char == '\n':
                fields.append("".join(current_field))
                yield fields
                fields = []
                current_field = []
                continue

            if not in_quotes and char == '\r':
                peek_char = stream.read(1)
                if peek_char == '\n':
                    fields.append("".join(current_field))
                    yield fields
                    fields = []
                    current_field = []
                else:
                    fields.append("".join(current_field))
                    yield fields

