class TaskScheduler:
    def __init__(self):
        self._tasks = []
        self._counter = 0
        self._removed = set()

    def add_task(self, task_name, delay=0):
        scheduled_time = time.time() + delay
        heapq.heappush(self._tasks, (scheduled_time, self._counter, task_name))
        self._counter += 1

    def remove_task(self, task_name):
        self._removed.add(task_name)

    def run(self):
        while self._tasks:
            scheduled_time, _, task_name = self._tasks[0]

            if task_name in self._removed:
                heapq.heappop(self._tasks)
                self._removed.remove(task_name)
                continue

            current_time = time.time()
            if current_time < scheduled_time:
                time.sleep(scheduled_time - current_time)

            heapq.heappop(self._tasks)
            print(f"Running task: {task_name}")

