type Task struct {
	ID    int
	Value int
}

type Result struct {
	TaskID int
	Result int
}

func Worker(id int, tasks <-chan Task, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for task := range tasks {
		results <- Result{
			TaskID: task.ID,
			Result: task.Value * task.Value,
		}
	}
}

func RunWorkerPool(numWorkers int, taskList []Task) []Result {
	tasks := make(chan Task, len(taskList))
	results := make(chan Result, len(taskList))
	var wg sync.WaitGroup

	for w := 1; w <= numWorkers; w++ {
		wg.Add(1)
		go Worker(w, tasks, results, &wg)
	}

	for _, task := range taskList {
		tasks <- task
	}
	close(tasks)

	wg.Wait()
	close(results)

	var allResults []Result
	for res := range results {
		allResults = append(allResults, res)
	}

	return allResults
}

func main() {
	tasks := []Task{
		{ID: 1, Value: 10},
		{ID: 2, Value: 20},
		{ID: 3, Value: 30},
		{ID: 4, Value: 40},
		{ID: 5, Value: 50},
	}

	results := RunWorkerPool(3, tasks)

	for _, res := range results {
		fmt.Printf("Task ID: %d, Result: %d\n", res.TaskID, res.Result)
	}
}

