def extractive_summarize(text, num_sentences=3):
    sentences = re.split(r'(?<=[.!?])\s+', text.strip())
    if len(sentences) <= num_sentences:
        return text.strip()

    words_in_sentences = []
    for s in sentences:
        words = re.findall(r'\b\w+\b', s.lower())
        words_in_sentences.append(words)

    all_words = [word for words in words_in_sentences for word in words]
    word_freq = Counter(all_words)
    max_freq = max(word_freq.values()) if word_freq else 1
    for word in word_freq:
        word_freq[word] /= max_freq

    def sentence_similarity(s1, s2):
        set1 = set(s1)
        set2 = set(s2)
        if len(set1) == 0 or len(set2) == 0:
            return 0.0
        common = set1.intersection(set2)
        return len(common) / (math.log(len(set1)) + math.log(len(set2)))

    similarity_matrix = nx.Graph()
    for i in range(len(sentences)):
        for j in range(len(sentences)):
            if i != j:
                sim = sentence_similarity(words_in_sentences[i], words_in_sentences[j])
                if sim > 0:
                    similarity_matrix.add_edge(i, j, weight=sim)

    scores = nx.pagerank(similarity_matrix, weight='weight')

    ranked_sentences = sorted(scores, key=lambda x: scores[x], reverse=True)
    selected_indices = sorted(ranked_sentences[:num_sentences])

    summary = ' '.join([sentences[i] for i in selected_indices])
    return summary

