def find_duplicates(items):
    seen = set()
    dups = []
    for item in items:
        if item in seen:
            if item not in dups:
                dups.append(item)
        else:
            seen.add(item)
    return dups

def coin_change(coins, amount):
    dp = [float('inf')] * (amount + 1)
    dp[0] = 0

    for coin in coins:
        for i in range(coin, amount + 1):
            dp[i] = min(dp[i], dp[i - coin] + 1)

    return dp[amount] if dp[amount] != float('inf') else -1

